-- Watchlist 1: Production Monitoring - grouped critical channels INSERT INTO watchlist (name, description, user_id, organization_id, configuration, filters, created_at, updated_at) SELECT 'Production Monitoring', 'Critical production services including backend errors, deployments, and security alerts. Configured for high-priority event tracking.', 1, NULL, jsonb_build_object( 'channelIds', jsonb_build_array( (SELECT id FROM channel WHERE name = 'Deployment Events' AND user_id = 1 AND organization_id IS NULL) ), 'groups', jsonb_build_array( jsonb_build_object( 'id', 'acc-g1-critical-services', 'name', 'Critical Services', 'channelIds', jsonb_build_array( (SELECT id FROM channel WHERE name = 'Backend Errors' AND user_id = 1 AND organization_id IS NULL), (SELECT id FROM channel WHERE name = 'Security Alerts' AND user_id = 1 AND organization_id IS NULL) ) ) ) ), jsonb_build_object( 'timeRange', '24h', 'onlyCritical', true, 'sortBySeverity', true, 'groupedView', true ), (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '40 days', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '2 hours';
-- Watchlist 2: Frontend Performance - single channel focus INSERT INTO watchlist (name, description, user_id, organization_id, configuration, filters, created_at, updated_at) SELECT 'Frontend Performance', 'Web application performance and user behavior tracking.', 1, NULL, jsonb_build_object( 'channelIds', jsonb_build_array( (SELECT id FROM channel WHERE name = 'Frontend Analytics' AND user_id = 1 AND organization_id IS NULL) ) ), jsonb_build_object( 'timeRange', '24h', 'onlyCritical', false, 'sortBySeverity', true, 'groupedView', true ), (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '35 days', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '1 day';
-- Watchlist 3: All Personal Channels - comprehensive overview with groups INSERT INTO watchlist (name, description, user_id, organization_id, configuration, filters, created_at, updated_at) SELECT 'All Channels Overview', 'Complete view of all personal channels organized by category.', 1, NULL, jsonb_build_object( 'channelIds', jsonb_build_array( (SELECT id FROM channel WHERE name = 'Marketing Campaigns' AND user_id = 1 AND organization_id IS NULL), (SELECT id FROM channel WHERE name = 'Test Channel' AND user_id = 1 AND organization_id IS NULL) ), 'groups', jsonb_build_array( jsonb_build_object( 'id', 'acc-g2-application', 'name', 'Application', 'channelIds', jsonb_build_array( (SELECT id FROM channel WHERE name = 'Backend Errors' AND user_id = 1 AND organization_id IS NULL), (SELECT id FROM channel WHERE name = 'Frontend Analytics' AND user_id = 1 AND organization_id IS NULL), (SELECT id FROM channel WHERE name = 'Mobile App Events' AND user_id = 1 AND organization_id IS NULL) ) ), jsonb_build_object( 'id', 'acc-g3-operations', 'name', 'Operations', 'channelIds', jsonb_build_array( (SELECT id FROM channel WHERE name = 'Deployment Events' AND user_id = 1 AND organization_id IS NULL), (SELECT id FROM channel WHERE name = 'Security Alerts' AND user_id = 1 AND organization_id IS NULL), (SELECT id FROM channel WHERE name = 'Scheduled Jobs' AND user_id = 1 AND organization_id IS NULL) ) ), jsonb_build_object( 'id', 'acc-g4-integrations', 'name', 'Integrations', 'channelIds', jsonb_build_array( (SELECT id FROM channel WHERE name = 'API Gateway Logs' AND user_id = 1 AND organization_id IS NULL), (SELECT id FROM channel WHERE name = 'Payment Processing' AND user_id = 1 AND organization_id IS NULL) ) ) ) ), jsonb_build_object( 'timeRange', '7d', 'onlyCritical', false, 'sortBySeverity', false, 'groupedView', true ), (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '30 days', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '5 minutes';
-- Watchlist 4: Security Focus INSERT INTO watchlist (name, description, user_id, organization_id, configuration, filters, created_at, updated_at) SELECT 'Security Alerts Only', 'Focused view for security monitoring. Shows only critical security events.', 1, NULL, jsonb_build_object( 'channelIds', jsonb_build_array( (SELECT id FROM channel WHERE name = 'Security Alerts' AND user_id = 1 AND organization_id IS NULL) ) ), jsonb_build_object( 'timeRange', '30d', 'onlyCritical', true, 'sortBySeverity', true, 'groupedView', true ), (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '25 days', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '30 minutes';
-- Watchlist 5: Mobile and Payments INSERT INTO watchlist (name, description, user_id, organization_id, configuration, filters, created_at, updated_at) SELECT 'Mobile and Payments Dashboard', 'Monitoring mobile app events alongside payment processing for end-to-end mobile commerce tracking.', 1, NULL, jsonb_build_object( 'channelIds', '[]'::jsonb, 'groups', jsonb_build_array( jsonb_build_object( 'id', 'acc-g5-mobile-commerce', 'name', 'Mobile Commerce', 'channelIds', jsonb_build_array( (SELECT id FROM channel WHERE name = 'Mobile App Events' AND user_id = 1 AND organization_id IS NULL), (SELECT id FROM channel WHERE name = 'Payment Processing' AND user_id = 1 AND organization_id IS NULL) ) ) ) ), jsonb_build_object( 'timeRange', '24h', 'onlyCritical', false, 'sortBySeverity', true, 'groupedView', true ), (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '20 days', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '4 hours';
-- Watchlist 6: DevOps Pipeline INSERT INTO watchlist (name, description, user_id, organization_id, configuration, filters, created_at, updated_at) SELECT 'DevOps Pipeline Monitor', 'Deployment events, scheduled jobs, and API gateway monitoring for DevOps visibility.', 1, NULL, jsonb_build_object( 'channelIds', '[]'::jsonb, 'groups', jsonb_build_array( jsonb_build_object( 'id', 'acc-g6-devops', 'name', 'DevOps', 'channelIds', jsonb_build_array( (SELECT id FROM channel WHERE name = 'Deployment Events' AND user_id = 1 AND organization_id IS NULL), (SELECT id FROM channel WHERE name = 'Scheduled Jobs' AND user_id = 1 AND organization_id IS NULL), (SELECT id FROM channel WHERE name = 'API Gateway Logs' AND user_id = 1 AND organization_id IS NULL) ) ) ) ), jsonb_build_object( 'timeRange', '24h', 'onlyCritical', false, 'sortBySeverity', true, 'groupedView', true ), (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '15 days', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '1 hour';

